/*
Emitted when an item of some 'id' is pressed. Also emitted when its accelerator is activated on macOS.

Note: If 'id' is negative (either explicitly or due to overflow), this will return the corresponding index instead.
*/
func (self Instance) OnIdPressed(cb func(id int), flags ...Signal.Flags) Instance {
	var flags_together Signal.Flags
	for _, flag := range flags {
		flags_together |= flag
	}
	gd.ObjectConnect(self.AsObject()[0], gd.NewStringName("id_pressed"), gd.NewCallable(cb), int64(flags_together))
	return self
}

func (self class) IdPressed() Signal.Any {
	return Signal.Via(gd.SignalProxy{}, pointers.Pack(gd.NewSignalOf(self.AsObject(), gd.NewStringName(`id_pressed`))))
}

